34	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	
37	const itemSurcharges = (item: Item): number => {
38	  const base = ITEM_TYPES[item.type].basePremium;
39	  let surcharge = 0;
40	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
