46	const basePremiumFor = (items: Item[]): number => {
47	  const groupBase = [...countByType(items)]
48	    .reduce((sum, [type, count]) => sum + basePremiumForGroup(type, count), 0);
49	  const itemSurchargeSum = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
50	  return groupBase + itemSurchargeSum;
