53	const percentOf = (amount: number, percent: number): number => (amount * percent) / 100;
54	
55	const applyFirstInsuranceSurcharge = (premium: number): number =>
56	  premium + percentOf(premium, FIRST_INSURANCE_SURCHARGE_PERCENT);
57	
58	const LOYALTY_DISCOUNT_PERCENT = 20;
59	const LOYALTY_MIN_YEARS = 2;
60	
61	const applyLoyaltyDiscount = (premium: number, yearsWithMHPCO: number): number =>
62	  yearsWithMHPCO >= LOYALTY_MIN_YEARS ? premium - percentOf(premium, LOYALTY_DISCOUNT_PERCENT) : premium;
63	
64	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
65	  const afterLoyalty = applyLoyaltyDiscount(basePremiumFor(items), yearsWithMHPCO);
66	  return Math.ceil(applyFirstInsuranceSurcharge(afterLoyalty)) + PROCESSING_FEE;
67	};
