69	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
70	  const years = scenario.customer.yearsWithMHPCO;
71	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items, years) }));
72	  return { results };
